import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { ShoppingCart, Trash2, Plus, Minus, ArrowLeft, CheckCircle } from 'lucide-react';
import { TIPOS_EMPAQUE } from '../data/mockData';

const PACKAGING_TYPES = [
  { key: 'fundas', label: 'Fundas de papel', emoji: '🛍️', description: 'Ligero y práctico' },
  { key: 'desechables', label: 'Desechable / plástico', emoji: '📦', description: 'Más rígido y protegido' },
  { key: 'canastos', label: 'Canastos', emoji: '🎁', description: 'Presentación premium' },
];

const ALL_PACKAGING_OPTIONS = PACKAGING_TYPES.flatMap(type =>
  (TIPOS_EMPAQUE[type.key] || []).map(option => ({ ...option, tipo: type.key }))
).sort((a, b) => a.capacidadMax - b.capacidadMax);

function getBestPackageForCount(count) {
  if (!ALL_PACKAGING_OPTIONS.length) return null;
  return ALL_PACKAGING_OPTIONS.find(option => count <= option.capacidadMax) || ALL_PACKAGING_OPTIONS[ALL_PACKAGING_OPTIONS.length - 1];
}

function getBestPackageForType(typeKey, count) {
  const options = (TIPOS_EMPAQUE[typeKey] || []).map(option => ({ ...option, tipo: typeKey }));
  if (!options.length) return null;
  return options.find(option => count <= option.capacidadMax) || options[options.length - 1];
}

export default function CartPage() {
  const { cart, removeFromCart, addToCart, clearCart, cartTotal, createOrder, currentUser } = useApp();
  const [selectedPackagingId, setSelectedPackagingId] = useState(() => getBestPackageForCount(0)?.id || '');
  const [customer, setCustomer] = useState(() => ({
    name: currentUser?.name || '',
    phone: '',
    address: '',
    reference: '',
  }));
  const [notes, setNotes] = useState('');
  const [success, setSuccess] = useState(null);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const selectedPackaging = ALL_PACKAGING_OPTIONS.find(option => option.id === selectedPackagingId) || getBestPackageForCount(cart.length);
  const selectedPackagingType = selectedPackaging?.tipo || 'fundas';
  const selectedPackagingOptions = TIPOS_EMPAQUE[selectedPackagingType] || [];

  useEffect(() => {
    if (!currentUser?.name) return;
    setCustomer(prev => (prev.name ? prev : { ...prev, name: currentUser.name }));
  }, [currentUser]);

  useEffect(() => {
    const recommended = getBestPackageForCount(cart.reduce((sum, item) => sum + item.qty, 0));
    if (!recommended) return;
    if (!selectedPackaging) {
      setSelectedPackagingId(recommended.id);
      return;
    }
    if (selectedPackaging.capacidadMax < cart.reduce((sum, item) => sum + item.qty, 0) && recommended.id !== selectedPackaging.id) {
      setSelectedPackagingId(recommended.id);
    }
  }, [cart, selectedPackaging]);

  const updateQty = (item, delta) => {
    if (item.qty + delta <= 0) return removeFromCart(item.productId);
    addToCart({ id: item.productId, name: item.name, price: item.price, image: item.image }, delta);
  };

  const totalItems = cart.reduce((sum, item) => sum + item.qty, 0);
  const packagingTotal = selectedPackaging?.precio || 0;
  const grandTotal = cartTotal + packagingTotal;

  const selectPackagingType = (typeKey) => {
    const bestMatch = getBestPackageForType(typeKey, totalItems) || getBestPackageForCount(totalItems);
    if (bestMatch) setSelectedPackagingId(bestMatch.id);
  };

  const confirm = () => {
    const trimmedName = customer.name.trim();
    const trimmedPhone = customer.phone.trim();
    const trimmedAddress = customer.address.trim();

    if (!selectedPackaging) {
      setError('Selecciona un empaque para continuar.');
      return;
    }

    if (!trimmedName || !trimmedPhone || !trimmedAddress) {
      setError('Completa tu nombre, teléfono y dirección antes de confirmar.');
      return;
    }

    setError('');
    const order = createOrder({
      notes,
      packaging: selectedPackaging,
      customer: { ...customer, name: trimmedName, phone: trimmedPhone, address: trimmedAddress },
    });
    setSuccess(order);
  };

  if (success) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '60vh', textAlign: 'center' }}>
        <div style={{ fontSize: '4rem', marginBottom: 16 }}>🎉</div>
        <div style={{ color: 'var(--success)', marginBottom: 12 }}><CheckCircle size={40} /></div>
        <h2 style={{ fontSize: '1.6rem', marginBottom: 8 }}>¡Pedido confirmado!</h2>
        <p style={{ color: 'var(--gray-400)', marginBottom: 6 }}>Tu pedido fue registrado exitosamente</p>
        {success.packaging && (
          <p style={{ color: 'var(--gray-500)', marginBottom: 6 }}>
            Empaque: {success.packaging.emoji} {success.packaging.nombre}
          </p>
        )}
        <p style={{ color: 'var(--pink-500)', fontWeight: 700, fontSize: '1.1rem', marginBottom: 28 }}>ID: {success.id}</p>
        <div style={{ display: 'flex', gap: 12 }}>
          <Link to="/mis-pedidos" className="btn btn-primary">Ver mis pedidos</Link>
          <Link to="/catalogo" className="btn btn-secondary">Seguir comprando</Link>
        </div>
      </div>
    );
  }

  if (cart.length === 0) {
    return (
      <div>
        <h1 style={{ marginBottom: 24 }}>Mi Carrito</h1>
        <div className="empty-state" style={{ padding: '80px 20px' }}>
          <span style={{ fontSize: '3rem' }}>🛒</span>
          <p>Tu carrito está vacío</p>
          <Link to="/catalogo" className="btn btn-primary" style={{ marginTop: 12 }}>Ver catálogo</Link>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div className="page-header">
        <div><h1>Mi Carrito</h1><p>{cart.length} productos</p></div>
        <Link to="/catalogo" className="btn btn-secondary"><ArrowLeft size={15} /> Seguir comprando</Link>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1.3fr 0.9fr', gap: 24, alignItems: 'start' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
          <div className="card" style={{ padding: '24px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', gap: 16, alignItems: 'flex-start', marginBottom: 18 }}>
              <div>
                <p style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--gray-400)', marginBottom: 4 }}>Paso 1</p>
                <h3 style={{ fontSize: '1.1rem' }}>Elige el empaque</h3>
                <p style={{ color: 'var(--gray-400)', fontSize: '0.88rem', marginTop: 4 }}>Si la cantidad supera la capacidad, se ajusta automáticamente a un empaque más grande.</p>
              </div>
              <div style={{ padding: '10px 14px', borderRadius: 14, background: 'var(--gray-50)', color: 'var(--gray-500)', fontSize: '0.86rem' }}>
                {totalItems} dulces seleccionados
              </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 10, marginBottom: 18 }}>
              {PACKAGING_TYPES.map(type => {
                const isActive = selectedPackagingType === type.key;
                return (
                  <button
                    key={type.key}
                    type="button"
                    onClick={() => selectPackagingType(type.key)}
                    style={{
                      textAlign: 'left',
                      padding: '14px 16px',
                      borderRadius: 'var(--radius-md)',
                      border: `1.5px solid ${isActive ? 'var(--pink-400)' : 'var(--gray-200)'}`,
                      background: isActive ? 'var(--pink-50)' : 'white',
                      cursor: 'pointer',
                    }}
                  >
                    <div style={{ fontSize: '1.2rem', marginBottom: 8 }}>{type.emoji}</div>
                    <div style={{ fontWeight: 700, marginBottom: 3 }}>{type.label}</div>
                    <div style={{ fontSize: '0.82rem', color: 'var(--gray-400)' }}>{type.description}</div>
                  </button>
                );
              })}
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(210px, 1fr))', gap: 10 }}>
              {selectedPackagingOptions.map(option => {
                const isActive = selectedPackagingId === option.id;
                return (
                  <button
                    key={option.id}
                    type="button"
                    onClick={() => setSelectedPackagingId(option.id)}
                    style={{
                      textAlign: 'left',
                      padding: '14px 16px',
                      borderRadius: 'var(--radius-md)',
                      border: `1.5px solid ${isActive ? 'var(--pink-400)' : 'var(--gray-200)'}`,
                      background: isActive ? 'var(--pink-50)' : 'white',
                      cursor: 'pointer',
                    }}
                  >
                    <div style={{ display: 'flex', justifyContent: 'space-between', gap: 12, alignItems: 'flex-start', marginBottom: 8 }}>
                      <div>
                        <div style={{ fontWeight: 700, marginBottom: 3 }}>{option.emoji} {option.nombre}</div>
                        <div style={{ fontSize: '0.82rem', color: 'var(--gray-400)' }}>{option.descripcion}</div>
                      </div>
                      <span style={{ fontWeight: 700, color: 'var(--pink-500)', whiteSpace: 'nowrap' }}>${option.precio.toFixed(2)}</span>
                    </div>
                    <div style={{ fontSize: '0.8rem', color: 'var(--gray-500)' }}>Capacidad: hasta {option.capacidadMax} dulces</div>
                  </button>
                );
              })}
            </div>
          </div>

          <div className="card">
            {cart.map(item => (
              <div key={item.productId} style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '18px 22px', borderBottom: '1px solid var(--gray-100)' }}>
                <span style={{ fontSize: '2.2rem' }}>{item.image}</span>
                <div style={{ flex: 1 }}>
                  <p style={{ fontWeight: 600, fontSize: '0.95rem' }}>{item.name}</p>
                  <p style={{ color: 'var(--pink-500)', fontWeight: 700 }}>${item.price.toFixed(2)}</p>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                  <button onClick={() => updateQty(item, -1)} className="btn btn-secondary btn-sm" style={{ width: 30, height: 30, padding: 0, justifyContent: 'center' }}><Minus size={13} /></button>
                  <span style={{ fontWeight: 700, minWidth: 24, textAlign: 'center' }}>{item.qty}</span>
                  <button onClick={() => updateQty(item, 1)} className="btn btn-secondary btn-sm" style={{ width: 30, height: 30, padding: 0, justifyContent: 'center' }}><Plus size={13} /></button>
                </div>
                <span style={{ fontWeight: 700, minWidth: 60, textAlign: 'right' }}>${(item.price * item.qty).toFixed(2)}</span>
                <button onClick={() => removeFromCart(item.productId)} className="btn btn-danger btn-sm" style={{ padding: '6px 8px' }}><Trash2 size={14} /></button>
              </div>
            ))}
          </div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
          <div className="card" style={{ padding: '24px' }}>
            <p style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--gray-400)', marginBottom: 4 }}>Paso 2</p>
            <h3 style={{ fontSize: '1.1rem', marginBottom: 16 }}>Datos personales</h3>

            <div className="form-group">
              <label>Nombre completo</label>
              <input value={customer.name} onChange={e => setCustomer(prev => ({ ...prev, name: e.target.value }))} placeholder="Nombre de quien hace el pedido" />
            </div>

            <div className="form-group">
              <label>Teléfono</label>
              <input value={customer.phone} onChange={e => setCustomer(prev => ({ ...prev, phone: e.target.value }))} placeholder="099 000 0000" />
            </div>

            <div className="form-group">
              <label>Dirección</label>
              <input value={customer.address} onChange={e => setCustomer(prev => ({ ...prev, address: e.target.value }))} placeholder="Calle, barrio o referencia" />
            </div>

            <div className="form-group">
              <label>Referencia extra</label>
              <input value={customer.reference} onChange={e => setCustomer(prev => ({ ...prev, reference: e.target.value }))} placeholder="Piso, casa color, horario, etc." />
            </div>

            <div className="form-group" style={{ marginTop: 18 }}>
              <label>Notas del pedido</label>
              <textarea value={notes} onChange={e => setNotes(e.target.value)} rows={3} placeholder="Ej: Sin nueces, para cumpleaños..." style={{ resize: 'none' }} />
            </div>

            {error && (
              <div style={{ background: '#fdecea', color: 'var(--danger)', borderRadius: 'var(--radius-md)', padding: '12px 14px', marginBottom: 14, fontSize: '0.88rem' }}>
                {error}
              </div>
            )}

            <button onClick={confirm} className="btn btn-primary btn-lg" style={{ width: '100%', justifyContent: 'center' }}>
              <ShoppingCart size={17} /> Confirmar pedido
            </button>
            <button onClick={clearCart} className="btn btn-danger" style={{ width: '100%', justifyContent: 'center', marginTop: 8 }}>
              Vaciar carrito
            </button>
          </div>

          <div className="card" style={{ padding: '24px' }}>
            <h3 style={{ fontSize: '1.1rem', marginBottom: 18 }}>Resumen del pedido</h3>

            {cart.map(item => (
              <div key={item.productId} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, fontSize: '0.88rem', color: 'var(--gray-500)' }}>
                <span>{item.name} x{item.qty}</span>
                <span>${(item.price * item.qty).toFixed(2)}</span>
              </div>
            ))}

            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, fontSize: '0.88rem', color: 'var(--gray-500)' }}>
              <span>Subtotal dulces</span>
              <span>${cartTotal.toFixed(2)}</span>
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, fontSize: '0.88rem', color: 'var(--gray-500)' }}>
              <span>Empaque</span>
              <span>{selectedPackaging ? `${selectedPackaging.emoji} ${selectedPackaging.nombre}` : 'Sin empaque'}</span>
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, fontSize: '0.88rem', color: 'var(--gray-500)' }}>
              <span>Costo empaque</span>
              <span>${packagingTotal.toFixed(2)}</span>
            </div>

            <div style={{ borderTop: '2px solid var(--gray-100)', marginTop: 14, paddingTop: 14, display: 'flex', justifyContent: 'space-between', fontWeight: 700, fontSize: '1.1rem' }}>
              <span>Total</span>
              <span style={{ color: 'var(--pink-500)' }}>${grandTotal.toFixed(2)}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
